UPDATE certifications
name = #{name}, issuing_organization = #{issuingOrganization}, issue_date = #{issueDate}, expiry_date = #{expiryDate}, credential_id = #{credentialId}, credential_url = #{credentialUrl}, sort_order = #{sortOrder},
WHERE id = #{id} AND resume_id = #{resumeId}

